CREATE TABLE IF NOT EXISTS vulnerabilities (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, cve_id VARCHAR(32) NOT NULL UNIQUE, description TEXT NOT NULL, severity VARCHAR(20) NOT NULL CHECK (severity IN ('low','medium','high','critical')), cvss_score DOUBLE PRECISION, risk_level VARCHAR(20) NOT NULL, affected_products JSONB NOT NULL DEFAULT '[]', published_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
